create table dirkspzm32.dis_cfg (
    sid                        varchar2(2 char) default '01' not null enable,
    firma_nr                   number default 1 not null enable,
    connector_name             varchar2(50 char) not null enable,
    connector_type             varchar2(20 char) default 'CON_IPS_FILE' not null enable,
    event_driven               varchar2(1 char) default 'F' not null enable,
    poll_interval_ms           number(*, 12) default 5000 not null enable,
    file_input_dir             varchar2(150 char),
    file_input_mask            varchar2(50 char),
    file_output_dir            varchar2(150 char),
    host_cfg_name              varchar2(50 char),
    isi_script_name            varchar2(50 char) not null enable,
    isi_script_file_input_func varchar2(50 char),
    enabled                    varchar2(1 char) default 'F' not null enable,
    hostname                   varchar2(150 char),
    app_exename                varchar2(150 char) default 'ISIPLUSDIS.EXE' not null enable,
    instance_id                number(*, 0) default 1 not null enable,
    loop_interval_ms           number(*, 12) default 1000 not null enable,
    event_type                 varchar2(20 char) default 'ET_EDGE' not null enable,
    connector_caption          varchar2(100 char),
    connector_desc             varchar2(2000 char),
    cfg_params                 varchar2(4000 char),
    process_data               varchar2(4000 char),
    isi_script_process_func    varchar2(50 char) default 'ProcessData',
    isi_script_display_func    varchar2(50 char) default 'DisplayData',
    p_connector_name           varchar2(50 char),
    dest_address               varchar2(150 char),
    dest_port                  number(*, 5) default 0 not null enable,
    uplink_port                number(*, 5) default 0 not null enable,
    service_port               number(*, 5) default 0 not null enable,
    usage                      varchar2(50 char) default 'UNKNOWN' not null enable,
    dest_address2              varchar2(150 char),
    dest_port2                 number(*, 5) default 0 not null enable,
    dest_address3              varchar2(150 char),
    dest_port3                 number(*, 5) default 0 not null enable
);

alter table dirkspzm32.dis_cfg
    add constraint check_dis_cfg_connector_type
        check ( connector_type in ( 'CON_IPS_FILE', 'CON_IPS_SAPRFC', 'CON_IPS_PCS' ) ) enable;

alter table dirkspzm32.dis_cfg
    add constraint check_dis_cfg_enabled
        check ( enabled in ( 'T', 'F' ) ) enable;

alter table dirkspzm32.dis_cfg
    add constraint check_dis_cfg_event_driven
        check ( event_driven in ( 'T', 'F' ) ) enable;

alter table dirkspzm32.dis_cfg
    add constraint check_dis_cfg_event_type
        check ( event_type in ( 'ET_EDGE', 'ET_PERIOD' ) ) enable;

alter table dirkspzm32.dis_cfg
    add constraint pk_dis_cfg
        primary key ( sid,
                      firma_nr,
                      connector_name )
            using index enable;


